[
    {
        "entity": "Beta-glucans",
        "behavior": "occur naturally as β-D-glucose polysaccharides",
        "context": "in the cell walls of cereals, bacteria, and fungi",
        "priority": 1
    },
    {
        "entity": "Beta-glucans",
        "behavior": "form a linear backbone with 1–3 β-glycosidic bonds",
        "context": "typically, though properties vary by source",
        "priority": 2
    },
    {
        "entity": "Oat fiber β-glucan",
        "behavior": "decreases blood levels of LDL cholesterol and reduces cardiovascular disease risk",
        "context": "at dietary intake levels of at least 3 g per day",
        "priority": 1
    },
    {
        "entity": "FDA",
        "behavior": "approved a health claim regarding β-glucan intake and reduced coronary heart disease risk",
        "context": "in 1997, specifically for oats and later amended to include barley",
        "priority": 2
    },
    {
        "entity": "Cellulose",
        "behavior": "is not conventionally considered a β-glucan",
        "context": "due to insolubility and differing physicochemical properties",
        "priority": 3
    },
    {
        "entity": "Yeast and fungal β-glucans",
        "behavior": "contain 1-6 side branches",
        "context": "distinguishing their structure from cereal β-glucans",
        "priority": 2
    },
    {
        "entity": "Cereal β-glucans",
        "behavior": "contain both β-1,3 and β-1,4 backbone bonds but no β-1,3 branching",
        "context": "within their molecular structure",
        "priority": 2
    },
    {
        "entity": "1,3-beta-glucan synthase",
        "behavior": "creates β-1,3 linkages",
        "context": "during the formation of glucan structures",
        "priority": 3
    },
    {
        "entity": "Beta-glucans",
        "behavior": "act as soluble, fermentable prebiotic fiber",
        "context": "in the diet within the large intestine",
        "priority": 1
    },
    {
        "entity": "Fermentation of β-glucans",
        "behavior": "produces short-chain fatty acids",
        "context": "as byproducts in the large intestine",
        "priority": 2
    },
    {
        "entity": "Cereal β-glucans",
        "behavior": "lower total and low-density lipoprotein cholesterol levels by 5 to 10%",
        "context": "in people with normal or elevated blood cholesterol levels",
        "priority": 1
    },
    {
        "entity": "Enterocytes",
        "behavior": "facilitate the transportation of β(1,3)-glucans",
        "context": "across the intestinal cell wall into the lymph",
        "priority": 2
    },
    {
        "entity": "Macrophages",
        "behavior": "interact with β-glucans to activate immune function",
        "context": "after absorption into the lymph",
        "priority": 2
    },
    {
        "entity": "M cells",
        "behavior": "transport insoluble whole glucan particles",
        "context": "into the gut-associated lymphoid tissue within Peyer's patches",
        "priority": 3
    },
    {
        "entity": "(1,3)-β-D-glucan assay",
        "behavior": "identifies invasive or disseminated fungal infections",
        "context": "by detecting the presence of (1,3)-β-D-glucan in blood",
        "priority": 2
    },
    {
        "entity": "(1,3)-β-D-glucan assay",
        "behavior": "can yield false positives",
        "context": "due to fungal contaminants in antibiotics or bacteria like Streptococcus pneumoniae",
        "priority": 3
    },
    {
        "entity": "Mucor and Rhizopus",
        "behavior": "are not detected by (1,3)-β-D-glucan assays",
        "context": "because they do not produce (1,3)-beta-D-glucan",
        "priority": 3
    }
]

