[
    {
        "entity": "Genome editing",
        "behavior": "targets insertions to site-specific locations",
        "context": "unlike early genetic engineering techniques that randomly insert genetic material",
        "priority": 1
    },
    {
        "entity": "Double-strand breaks (DSBs)",
        "behavior": "are repaired through homology-directed recombination (HDR) or non-homologous end joining (NHEJ)",
        "context": "the basic mechanism involved in genetic manipulations through programmable nucleases",
        "priority": 1
    },
    {
        "entity": "CRISPR gene editing",
        "behavior": "improved the efficiency, specificity, and practicality of large-scale genome editing",
        "context": "development in 2015",
        "priority": 1
    },
    {
        "entity": "Meganucleases",
        "behavior": "recognize and cut large DNA sequences (from 14 to 40 base pairs)",
        "context": "enzymes in the endonuclease family discovered in the late 1980s",
        "priority": 2
    },
    {
        "entity": "Zinc finger nucleases (ZFNs)",
        "behavior": "link specific DNA sequence recognizing peptides to a non-specific FokI endonuclease domain",
        "context": "relies on modular assembly of zinc fingers that generally recognize 3 base pairs each",
        "priority": 1
    },
    {
        "entity": "TALENs",
        "behavior": "utilize arrays of 33 or 34-amino acid repeats where RVDs determine binding to specific nucleotides",
        "context": "offer higher DNA binding specificity and lower off-target effects than ZFNs",
        "priority": 1
    },
    {
        "entity": "CRISPR/Cas9 system",
        "behavior": "uses RNA guides to direct Cas proteins to cut matching viral or target DNA sequences",
        "context": "derived from bacterial acquired immunity elements",
        "priority": 1
    },
    {
        "entity": "Base editing",
        "behavior": "employs nucleobase modifying enzymes to enable precise editing without breaking genomic DNA strands",
        "context": "avoids random insertion and deletions associated with DSB repair",
        "priority": 2
    },
    {
        "entity": "MAGE (Multiplex Automated Genomic Engineering)",
        "behavior": "uses synthetic ssDNA and oligonucleotides to introduce combinatorial genetic diversity",
        "context": "allows simultaneous modification of multiple genomic sites in a machine-driven process",
        "priority": 2
    },
    {
        "entity": "He Jiankui",
        "behavior": "created the first humans born from genome-edited embryos",
        "context": "a controversial 2019 affair involving the disabling of the CCR5 gene",
        "priority": 2
    },
    {
        "entity": "Homologous recombination (HR)",
        "behavior": "inserts constructs at a desired location using a template matching the targeted sequence",
        "context": "early gene targeting method used on embryonic stem cells",
        "priority": 2
    },
    {
        "entity": "Non-homologous end joining (NHEJ)",
        "behavior": "directly joins DNA ends after a break",
        "context": "an error-prone repair pathway often exploited for gene disruption",
        "priority": 2
    },
    {
        "entity": "Mario Capecchi, Martin Evans and Oliver Smithies",
        "behavior": "were awarded the Nobel Prize for Physiology or Medicine",
        "context": "in 2007 for discoveries regarding gene modifications in mice using embryonic stem cells",
        "priority": 3
    },
    {
        "entity": "Emmanuelle Charpentier and Jennifer Doudna",
        "behavior": "were awarded the Nobel Prize in Chemistry",
        "context": "in 2020 for the development of a method for genome editing",
        "priority": 2
    },
    {
        "entity": "Gene drives",
        "behavior": "alter the reproductive rate or traits of populations, such as inducing sterility",
        "context": "potential tool for eradicating vector-borne diseases like malaria in mosquitoes",
        "priority": 2
    },
    {
        "entity": "OMEGA proteins",
        "behavior": "act as transposon-guided endonucleases",
        "context": "announced in 2021 as a CRISPR alternative",
        "priority": 3
    },
    {
        "entity": "ARCUT",
        "behavior": "uses pseudo-complementary peptide nucleic acid and chemical mixtures to excise DNA",
        "context": "an artificial restriction DNA cutter technique",
        "priority": 3
    }
]

[
    {
        "entity": "Common envelope jets supernova (CEJSN)",
        "behavior": "is caused by the merger of a giant or supergiant star with a compact star such as a neutron star or a black hole",
        "context": "definition of the explosion type",
        "priority": 1
    },
    {
        "entity": "Compact star",
        "behavior": "plunges into the envelope, accretes matter, and launches jets that can disrupt the envelope",
        "context": "during the merger process with a giant/supergiant",
        "priority": 1
    },
    {
        "entity": "iPTF14hls",
        "behavior": "is explained by the CEJSN model",
        "context": "as a binary star system where a neutron star plunged into a giant star's envelope",
        "priority": 2
    },
    {
        "entity": "Jets",
        "behavior": "emanate from polar areas, have masses of a fraction of a solar mass, and move near the speed of light",
        "context": "produced by the compact star during accretion",
        "priority": 2
    },
    {
        "entity": "Giant star envelope",
        "behavior": "is ejected over a timespan of a few hundred days",
        "context": "after being inflated by jet-created bubbles ('cocoons')",
        "priority": 2
    },
    {
        "entity": "Gravitational waves",
        "behavior": "are produced",
        "context": "when the core of the giant is consumed by the compact star",
        "priority": 2
    },
    {
        "entity": "Black hole",
        "behavior": "may be the source of cosmic ultra-high-energy neutrinos",
        "context": "when it acts as the incoming compact star in a CEJSN",
        "priority": 3
    },
    {
        "entity": "Tidal acceleration",
        "behavior": "causes the giant's envelope to expand and potentially clear polar regions",
        "context": "before the actual penetration and merger begins",
        "priority": 2
    },
    {
        "entity": "Accretion disk",
        "behavior": "forms around the neutron star",
        "context": "a key requirement for the generation of jets in a CEJSN",
        "priority": 2
    },
    {
        "entity": "Neutrinos",
        "behavior": "carry away large amounts of energy",
        "context": "facilitating the high accretion rates required for the process",
        "priority": 2
    },
    {
        "entity": "r-process nucleosynthesis",
        "behavior": "takes place in the jets",
        "context": "making CEJSNs a potential source of elements heavier than lanthanides early in the universe's history",
        "priority": 2
    },
    {
        "entity": "Reticulum II",
        "behavior": "has r-process element enrichment that may be explained by a CEJSN",
        "context": "an example of the nucleosynthesis impact on galaxies",
        "priority": 3
    },
    {
        "entity": "Fast blue optical transients",
        "behavior": "might constitute CEJSNs",
        "context": "classification of other potential examples",
        "priority": 3
    },
    {
        "entity": "Supernova impostor",
        "behavior": "occurs if the giant star survives the interaction",
        "context": "such as in events like SN 2009ip and AT2018cow",
        "priority": 2
    },
    {
        "entity": "Binary neutron stars",
        "behavior": "may be formed from a stripped core that eventually goes supernova",
        "context": "following a non-destructive CEJSN interaction",
        "priority": 2
    }
]

