[
    {
        "entity": "Fecal microbiota transplant (FMT)",
        "behavior": "is an effective treatment for Clostridioides difficile infection (CDI)",
        "context": "being more effective than vancomycin alone for recurrent CDI and potentially improving outcomes after the first index infection",
        "priority": 1
    },
    {
        "entity": "Fecal microbiota transplant (FMT)",
        "behavior": "demonstrates approximately 85–90% effectiveness",
        "context": "in people with CDI for whom antibiotics have not worked or in whom the disease recurs following antibiotics",
        "priority": 1
    },
    {
        "entity": "Ulcerative colitis",
        "behavior": "requires multiple and recurrent infusions to achieve prolonged remission",
        "context": "unlike C. difficile which is generally eradicated with a single FMT infusion",
        "priority": 2
    },
    {
        "entity": "Biomictra, Rebyota, and Vowst",
        "behavior": "were approved for medical use",
        "context": "in Australia and the United States between 2022 and 2023, with Vowst being the first oral product",
        "priority": 2
    },
    {
        "entity": "Sterile fecal filtrate",
        "behavior": "demonstrated comparable efficacy to conventional FMT",
        "context": "in a pilot study, suggesting soluble components like bacteriophages or metabolites may be key mediators rather than intact bacteria",
        "priority": 2
    },
    {
        "entity": "Adverse effects",
        "behavior": "include bacterial blood infections, mild GI distress, and potential transmission of drug-resistant organisms",
        "context": "leading to FDA warnings after a patient death in 2019 due to improperly screened donor stool",
        "priority": 2
    },
    {
        "entity": "FMT for Obesity",
        "behavior": "resulted in an 11.2kg weight difference compared to placebo",
        "context": "in a 2025 New Zealand study of 87 obese adolescents after four years",
        "priority": 2
    },
    {
        "entity": "FDA",
        "behavior": "regulates human fecal material as a biological product and drug",
        "context": "requiring an Investigational New Drug (IND) application for uses other than recurrent C. difficile infections",
        "priority": 2
    },
    {
        "entity": "Hong Ge",
        "behavior": "recorded the first use of donor feces as a therapeutic agent",
        "context": "in 4th century China for food poisoning and diarrhea",
        "priority": 3
    },
    {
        "entity": "Transfaunation",
        "behavior": "is the term for fecal microbiota transplant in veterinary medicine",
        "context": "used to treat ruminating animals by feeding them rumen contents from a healthy animal",
        "priority": 3
    }
]

